class MockZap:
    def __init__(self, trigger_name):
        self.trigger = trigger_name
        self.actions = []

    def add_action(self, action_func):
        self.actions.append(action_func)

    def run(self, data):
        print(f"--- Zap Triggered by: {self.trigger} ---")
        print(f"Data: {data}")
        for action in self.actions:
            action(data)

def send_slack(data):
    print(f"[Slack] New Lead: {data['name']}")

def add_to_crm(data):
    print(f"[CRM] Added {data['name']} to Sales Pipeline.")

zap = MockZap("New Google Sheet Row")
zap.add_action(send_slack)
zap.add_action(add_to_crm)

# Trigger event happens
zap.run({'name': 'Alice Smith', 'email': 'alice@example.com'})

